/**
 * Revenue sharing calculations for partner payouts.
 *
 * Formula: payout = (transactionAmount - platformFeeAmount) * partnerSharePercentage
 * where platformFeeAmount = transactionAmount * platformFeePercentage
 *
 * Result is floor-rounded to the nearest cent to avoid overpaying partners.
 */

/**
 * Calculate the partner payout for a given transaction.
 *
 * @param transactionAmount     - Gross transaction amount in dollars (e.g. 100.00)
 * @param platformFeePercentage - Platform fee as a decimal fraction (e.g. 0.05 for 5%)
 * @param partnerSharePercentage - Partner's share of the net amount as a decimal fraction (e.g. 0.70 for 70%)
 * @returns Partner payout in dollars, floor-rounded to the nearest cent
 */
export function calculatePartnerPayout(
  transactionAmount: number,
  platformFeePercentage: number,
  partnerSharePercentage: number
): number {
  // AC2: platform fee amount derived from transaction amount and fee percentage
  const platformFeeAmount = transactionAmount * platformFeePercentage;

  // AC1: payout = (transaction_amount - platform_fee_amount) * partner_share_percentage
  const netAmount = transactionAmount - platformFeeAmount;
  const rawPayout = netAmount * partnerSharePercentage;

  // AC4: floor-round to nearest cent — never overpay by rounding up fractional cents
  return Math.floor(rawPayout * 100) / 100;
}

