/**
 * Revenue sharing calculation for partner payouts.
 *
 * Formula:
 *   platform_fee_amount  = transactionAmount * platformFeePercentage
 *   partner_payout       = (transactionAmount - platform_fee_amount) * partnerSharePercentage
 *
 * Result is floored to the nearest cent to avoid overpaying partners.
 *
 * @param transactionAmount       - Gross transaction amount in dollars (e.g. 100.00)
 * @param platformFeePercentage   - Platform fee as a decimal fraction (e.g. 0.05 = 5%)
 * @param partnerSharePercentage  - Partner share as a decimal fraction (e.g. 0.70 = 70%)
 * @returns Partner payout in dollars, floored to the nearest cent
 */
export function calculatePartnerPayout(
  transactionAmount: number,
  platformFeePercentage: number,
  partnerSharePercentage: number
): number {
  const platformFeeAmount = transactionAmount * platformFeePercentage;
  const netAmount = transactionAmount - platformFeeAmount;
  const rawPayout = netAmount * partnerSharePercentage;

  // Floor to nearest cent — never overpay partners due to fractional cents.
  // Multiply by 100, floor, then divide back to preserve dollar representation.
  return Math.floor(rawPayout * 100) / 100;
}

